import{_ as e,o as a,c as r,a2 as s}from"./chunks/framework.DvFsUg-r.js";const v=JSON.parse('{"title":"종합 분석 보고서","description":"","frontmatter":{},"headers":[],"relativePath":"hermes/overview.md","filePath":"hermes/overview.md","lastUpdated":1781092690000}'),d={name:"hermes/overview.md"};function i(o,t,l,n,c,h){return a(),r("div",null,[...t[0]||(t[0]=[s('<h1 id="종합-분석-보고서" tabindex="-1">종합 분석 보고서 <a class="header-anchor" href="#종합-분석-보고서" aria-label="Permalink to &quot;종합 분석 보고서&quot;">​</a></h1><div class="badge-box"><span class="badge-red">v0.8.0 · The Intelligence Release</span><span class="badge-teal">MIT License</span><span class="badge-gold">2026-04-08</span><span class="badge-green">7 Releases · 6주</span></div><div class="tip custom-block"><p class="custom-block-title">코드 복사 · 붙여넣기</p><p>이 문서의 코드 블록에는 복사 버튼이 없습니다. <strong>복사</strong>는 코드 블록을 드래그 선택 후 <strong>마우스 오른쪽 클릭</strong>, <strong>붙여넣기</strong>는 터미널에서 <strong><code>Ctrl+Shift+V</code></strong> (macOS는 <code>Cmd+V</code>)를 사용하세요.</p></div><blockquote><p>&quot;유일하게 내장 학습 루프를 갖춘 오픈소스 에이전트&quot; — Nous Research가 내세우는 이 문구는 과장이 아닙니다. v0.2.0 최초 공개 이후 6주 만에 일곱 번의 메이저 릴리스를 내며 백그라운드 자동 알림, 프로파일 다중 인스턴스, OpenAI 호환 API 서버, Gemini 네이티브 프로바이더 등을 더했습니다. 이 보고서는 그 기술적 실체를 낱낱이 분석합니다.</p></blockquote><h2 id="프로젝트-정체성" tabindex="-1">프로젝트 정체성 <a class="header-anchor" href="#프로젝트-정체성" aria-label="Permalink to &quot;프로젝트 정체성&quot;">​</a></h2><p><strong>Hermes Agent</strong>는 <a href="https://nousresearch.com" target="_blank" rel="noreferrer">Nous Research</a>가 개발·유지하는 자기개선(self-improving) AI 에이전트 프레임워크입니다. &quot;LLM 래퍼&quot; 혹은 &quot;도구 호출 오케스트레이터&quot;라는 기존 카테고리로는 이 프로젝트의 가치를 설명하기 어렵습니다. 정확한 포지셔닝은 다음과 같습니다.</p><div class="pull"> Hermes Agent는 <strong>에이전트가 경험으로부터 절차적 지식(스킬)을 추출·축적·개선하는 폐쇄 루프</strong>를 갖춘 범용 실행 환경입니다. 쓸수록 특정 도메인에 최적화되며, 사용자·팀·프로젝트별 맥락을 레이어드 프롬프트로 관리합니다. </div><p>이 보고서에서 집중적으로 다룰 세 가지 축:</p><ol><li><strong>학습 루프</strong> — 트라젝토리를 스킬로 변환해 재사용 가능한 지식 자산으로 만드는 메커니즘</li><li><strong>재사용성 아키텍처</strong> — 스킬, 프롬프트 레이어, 메모리, 슬래시 명령이 서로 보완하는 구조</li><li><strong>범용 실행 환경</strong> — 모델·플랫폼·백엔드 무관 설계로 개인부터 엔터프라이즈까지 커버</li></ol><h2 id="프로젝트-통계" tabindex="-1">프로젝트 통계 <a class="header-anchor" href="#프로젝트-통계" aria-label="Permalink to &quot;프로젝트 통계&quot;">​</a></h2><div class="stat-grid"><div class="stat-card"><div class="stat-number">53.1k</div><div class="stat-label">GitHub Stars</div></div><div class="stat-card"><div class="stat-number">375</div><div class="stat-label">Contributors</div></div><div class="stat-card"><div class="stat-number">7</div><div class="stat-label">Major Releases</div></div><div class="stat-card"><div class="stat-number">6주</div><div class="stat-label">공개 이후 기간</div></div><div class="stat-card"><div class="stat-number">40+</div><div class="stat-label">내장 도구</div></div><div class="stat-card"><div class="stat-number">643</div><div class="stat-label">스킬 허브</div></div><div class="stat-card"><div class="stat-number">15+</div><div class="stat-label">플랫폼</div></div><div class="stat-card"><div class="stat-number">400+</div><div class="stat-label">LLM 모델 (Nous Portal)</div></div></div><h2 id="v0-8-0-주요-신기능-the-intelligence-release" tabindex="-1">v0.8.0 주요 신기능 (The Intelligence Release) <a class="header-anchor" href="#v0-8-0-주요-신기능-the-intelligence-release" aria-label="Permalink to &quot;v0.8.0 주요 신기능 (The Intelligence Release)&quot;">​</a></h2><div class="timeline"><div class="timeline-item"><strong>백그라운드 프로세스 자동 알림</strong> — 긴 작업이 끝나면 에이전트에 자동 알림(<code>notify_on_complete</code>). 폴링 없이 능동 대화 이어가기. </div><div class="timeline-item"><strong>라이브 <code>/model</code> 전환</strong> — CLI·Telegram·Discord·Slack 어디서든 세션 유지하며 모델 교체. </div><div class="timeline-item"><strong>Google AI Studio (Gemini) 네이티브</strong> — models.dev 자동 레지스트리로 모델 메타 실시간 감지. </div><div class="timeline-item"><strong>자가 최적화 GPT/Codex 지침</strong> — 행동 벤치마킹으로 모델별 도구 사용 규칙 자동 생성. </div><div class="timeline-item"><strong>Slack·Telegram 네이티브 승인 버튼</strong> — 인라인 버튼으로 매끄러운 승인 UX. </div><div class="timeline-item"><strong>MCP OAuth 2.1 + OSV 악성코드 스캐닝</strong> — 서드파티 MCP 서버 공급망 공격 차단. </div><div class="timeline-item"><strong>중앙 로깅 시스템</strong> — <code>~/.hermes/logs/</code> + <code>hermes logs</code> 명령. </div><div class="timeline-item"><strong>Matrix Tier 1 하드닝</strong> — 리액션·읽음 확인 등 네이티브 기능 완성. </div></div><p>전체 릴리스 히스토리는 <a href="/hermes/whats-new/">최신 기능 &amp; 릴리스 타임라인</a> 참조.</p><h2 id="기술-스택" tabindex="-1">기술 스택 <a class="header-anchor" href="#기술-스택" aria-label="Permalink to &quot;기술 스택&quot;">​</a></h2><table tabindex="0"><thead><tr><th>항목</th><th>상세</th></tr></thead><tbody><tr><td><strong>주 언어</strong></td><td>Python 3.11+ (93.8%)</td></tr><tr><td><strong>패키지 관리</strong></td><td>uv (Astral) — 빠른 Python 패키징</td></tr><tr><td><strong>프론트엔드 CLI</strong></td><td>prompt-toolkit 기반 TUI (멀티라인, 자동완성, 스트리밍)</td></tr><tr><td><strong>AI SDK</strong></td><td>OpenAI SDK ≥2.21.0, Anthropic SDK ≥0.39.0</td></tr><tr><td><strong>HTTP</strong></td><td>httpx (async), tenacity (재시도)</td></tr><tr><td><strong>데이터 검증</strong></td><td>Pydantic v2</td></tr><tr><td><strong>비동기</strong></td><td>asyncio 전면 — 프리페치, 병렬 도구 호출</td></tr><tr><td><strong>상태 저장</strong></td><td>SQLite (state.db), Markdown (MEMORY.md, SOUL.md, USER.md, AGENTS.md)</td></tr><tr><td><strong>전문 검색</strong></td><td>SQLite FTS5 + 선택적 임베딩 (sentence-transformers)</td></tr><tr><td><strong>실행 환경</strong></td><td>Docker, Singularity, Modal, Daytona, SSH, Local</td></tr><tr><td><strong>사용자 모델링</strong></td><td>Honcho (변증법적 dialectic 추론)</td></tr><tr><td><strong>플러그인</strong></td><td>이벤트 훅 시스템</td></tr><tr><td><strong>라이선스</strong></td><td>MIT (상업적 사용 무제한)</td></tr></tbody></table><h2 id="_5-레이어-아키텍처-요약" tabindex="-1">5-레이어 아키텍처 요약 <a class="header-anchor" href="#_5-레이어-아키텍처-요약" aria-label="Permalink to &quot;5-레이어 아키텍처 요약&quot;">​</a></h2><p>Hermes Agent의 시스템은 다섯 개의 독립된 레이어로 구성됩니다. 각 레이어는 상위 레이어에만 의존하며, 교체·확장이 가능합니다.</p><h3 id="_1-interface-layer-—-사용자-접점" tabindex="-1">1. Interface Layer — 사용자 접점 <a class="header-anchor" href="#_1-interface-layer-—-사용자-접점" aria-label="Permalink to &quot;1. Interface Layer — 사용자 접점&quot;">​</a></h3><p>CLI(TUI) · Gateway(15+ 메시징 플랫폼) · ACP(IDE 통합) · Cron(스케줄) · Web API.</p><h3 id="_2-agent-core-—-두뇌" tabindex="-1">2. Agent Core — 두뇌 <a class="header-anchor" href="#_2-agent-core-—-두뇌" aria-label="Permalink to &quot;2. Agent Core — 두뇌&quot;">​</a></h3><p>Conversation Manager, System Prompt Builder(레이어드), Context Window Manager, Tool Orchestrator, Approval Gate, Trajectory Recorder, Model Provider Abstraction.</p><h3 id="_3-capability-layer-—-역량" tabindex="-1">3. Capability Layer — 역량 <a class="header-anchor" href="#_3-capability-layer-—-역량" aria-label="Permalink to &quot;3. Capability Layer — 역량&quot;">​</a></h3><p>47+ 도구 · 643+ 스킬 · 플러그인 · MCP 클라이언트 · 스크립트 RPC.</p><h3 id="_4-persistence-layer-—-기억" tabindex="-1">4. Persistence Layer — 기억 <a class="header-anchor" href="#_4-persistence-layer-—-기억" aria-label="Permalink to &quot;4. Persistence Layer — 기억&quot;">​</a></h3><p>Memory(MEMORY.md, USER.md), Session(state.db), Honcho Peers, Trajectory Store.</p><h3 id="_5-execution-layer-—-실행" tabindex="-1">5. Execution Layer — 실행 <a class="header-anchor" href="#_5-execution-layer-—-실행" aria-label="Permalink to &quot;5. Execution Layer — 실행&quot;">​</a></h3><p>Local · Docker · SSH · Daytona · Singularity · Modal 6종 백엔드.</p><p>자세한 내부 구조는 <a href="/hermes/advanced/architecture">시스템 아키텍처</a> 참조.</p><h2 id="핵심-기능-매트릭스" tabindex="-1">핵심 기능 매트릭스 <a class="header-anchor" href="#핵심-기능-매트릭스" aria-label="Permalink to &quot;핵심 기능 매트릭스&quot;">​</a></h2><table tabindex="0"><thead><tr><th>기능 영역</th><th>세부 기능</th><th>차별화 포인트</th></tr></thead><tbody><tr><td><strong>학습 루프</strong></td><td>트라젝토리 → 스킬 자동 추출·개선</td><td>업계 유일 내장 폐쇄 루프</td></tr><tr><td><strong>스킬 시스템</strong></td><td>643+ 디렉토리 기반 번들, progressive disclosure</td><td>합성 가능성, 오픈 표준</td></tr><tr><td><strong>프롬프트 관리</strong></td><td>SOUL/USER/AGENTS 4계층, 프롬프트 캐싱</td><td>레이어별 수명 주기 분리</td></tr><tr><td><strong>메모리</strong></td><td>MEMORY.md 큐레이션 + 전문 검색 + Honcho 피어</td><td>변증법적 사용자 모델링</td></tr><tr><td><strong>멀티 플랫폼</strong></td><td>15+ 메시징 + CLI + IDE + Cron</td><td>세션 연속성 보장</td></tr><tr><td><strong>도구</strong></td><td>47+ 원자 도구 + MCP 확장 + 스크립트 RPC</td><td>통합 카탈로그, 병렬 실행</td></tr><tr><td><strong>실행 환경</strong></td><td>6종 백엔드, 하이버네이션 지원</td><td>$5 VPS ~ HPC 스펙트럼</td></tr><tr><td><strong>모델 유연성</strong></td><td>200+ 모델, 슬래시 명령 즉시 전환</td><td>프로바이더 lock-in 회피</td></tr><tr><td><strong>자동화</strong></td><td>자연어 크론 스케줄러</td><td>크로스 플랫폼 결과 라우팅</td></tr><tr><td><strong>병렬 처리</strong></td><td>서브에이전트 스폰, 격리 컨텍스트</td><td>분할 정복 작업</td></tr><tr><td><strong>보안</strong></td><td>도구별 승인 게이트, DM 페어링, 격리, 의존성 핀닝</td><td>프로덕션급 다층 방어</td></tr></tbody></table><h2 id="사용자-시나리오" tabindex="-1">사용자 시나리오 <a class="header-anchor" href="#사용자-시나리오" aria-label="Permalink to &quot;사용자 시나리오&quot;">​</a></h2><h3 id="개인-개발자" tabindex="-1">개인 개발자 <a class="header-anchor" href="#개인-개발자" aria-label="Permalink to &quot;개인 개발자&quot;">​</a></h3><ul><li>CLI + ACP로 IDE 안팎에서 동일 에이전트</li><li>슬래시 명령으로 자주 하는 작업 저장</li><li>학습 루프가 자동으로 스킬화</li></ul><h3 id="팀-조직" tabindex="-1">팀 / 조직 <a class="header-anchor" href="#팀-조직" aria-label="Permalink to &quot;팀 / 조직&quot;">​</a></h3><ul><li><code>.hermes/AGENTS.md</code> 커밋으로 팀 규약 공유</li><li>프로젝트 스킬(<code>&lt;proj&gt;/.hermes/skills/</code>)로 공통 워크플로우</li><li>Slack/Discord 게이트웨이로 팀 채널에 에이전트 배치</li><li>도구 승인 정책으로 안전 경계 통제</li></ul><h3 id="연구자" tabindex="-1">연구자 <a class="header-anchor" href="#연구자" aria-label="Permalink to &quot;연구자&quot;">​</a></h3><ul><li>배치 트라젝토리 생성 → SFT/RL 데이터셋</li><li>tinker-atropos 통합 RL 파이프라인</li><li>wandb 추적, 모델별 eval 자동화</li><li>Singularity 백엔드로 HPC 클러스터 활용</li></ul><h3 id="인프라-엔지니어" tabindex="-1">인프라 엔지니어 <a class="header-anchor" href="#인프라-엔지니어" aria-label="Permalink to &quot;인프라 엔지니어&quot;">​</a></h3><ul><li>Docker 샌드박스로 격리 실행</li><li>Modal 서버리스로 부하 탄력 대응</li><li>SSH 원격 실행으로 중앙 집중 관리</li><li>크론 + 서브에이전트로 대규모 인프라 모니터링</li></ul><h2 id="재사용성-철학" tabindex="-1">재사용성 철학 <a class="header-anchor" href="#재사용성-철학" aria-label="Permalink to &quot;재사용성 철학&quot;">​</a></h2><p>이 프로젝트의 설계를 관통하는 일관된 주제는 **&quot;한 번 만든 자산을 여러 곳에서 쓸 수 있게&quot;**입니다. 이것은 구호가 아니라 아키텍처의 핵심이며, 다음 네 가지 메커니즘으로 구현됩니다.</p><ol><li><strong>레이어드 프롬프트</strong> — 개인/팀/프로젝트/환경을 파일 시스템으로 분리</li><li><strong>스킬 번들</strong> — 절차, 스크립트, 예시, 테스트를 한 디렉토리에 캡슐화</li><li><strong>Progressive disclosure</strong> — 카탈로그만 상주, 본문은 필요 시 lazy load</li><li><strong>학습 루프</strong> — 써보면서 개선, 개선이 자산에 누적</li></ol><p>자세한 패턴은 <a href="/hermes/reusability/patterns">재사용성 패턴</a> 참조.</p><h2 id="생태계-커뮤니티" tabindex="-1">생태계 &amp; 커뮤니티 <a class="header-anchor" href="#생태계-커뮤니티" aria-label="Permalink to &quot;생태계 &amp; 커뮤니티&quot;">​</a></h2><dl class="kv"><dt>Skills Hub</dt><dd><a href="https://agentskills.io">agentskills.io</a> — 643개 스킬, 16개 카테고리, 벤더 중립 오픈 표준</dd><dt>Discord</dt><dd><a href="https://discord.gg/NousResearch">discord.gg/NousResearch</a> — 개발·연구 커뮤니티</dd><dt>OpenClaw 마이그레이션</dt><dd>기존 OpenClaw 사용자를 위한 자동 전환 도구(<code>hermes claw migrate</code>)</dd><dt>MCP 생태계</dt><dd>Anthropic 주도 Model Context Protocol 생태계와 완전 호환</dd><dt>기여</dt><dd>MIT 라이선스, 331명 기여자 — 활발한 PR 리뷰와 이슈 트리아지</dd></dl><h2 id="보고서-읽는-법" tabindex="-1">보고서 읽는 법 <a class="header-anchor" href="#보고서-읽는-법" aria-label="Permalink to &quot;보고서 읽는 법&quot;">​</a></h2><p>처음 읽는다면 다음 순서를 권장합니다.</p><ol><li><strong><a href="/hermes/executive-summary">핵심 요약</a></strong> — SWOT, 권장사항, 종합 점수</li><li><strong><a href="/hermes/features/learning-loop">학습 루프</a></strong> — 프로젝트의 핵심 가치 제안</li><li><strong><a href="/hermes/features/skills">스킬 시스템</a></strong> — 학습 루프의 구체적 산물</li><li><strong><a href="/hermes/reusability/prompts">프롬프트 관리</a></strong> — 재사용성의 실질</li><li><strong><a href="/hermes/advanced/architecture">시스템 아키텍처</a></strong> — 모든 것이 어떻게 엮이는지</li><li><strong><a href="/hermes/analysis/market-position">시장 포지셔닝</a></strong> — 경쟁 지형</li><li><strong><a href="/hermes/analysis/conclusion">종합 평가</a></strong> — 도입 판단 자료</li></ol><p>특정 역할별 추천 경로:</p><div class="two-col"><div class="col-card"><h4>엔지니어링 리더</h4><ol><li>핵심 요약</li><li>재사용성 패턴</li><li>보안 체계</li><li>종합 평가</li></ol></div><div class="col-card"><h4>개발자 · 사용자</h4><ol><li>설치 가이드</li><li>학습 루프 + 스킬</li><li>프롬프트 관리</li><li>슬래시 명령</li></ol></div></div>',51)])])}const m=e(d,[["render",i]]);export{v as __pageData,m as default};
